package com.trademaster.ims.mobile.checkout.model;
import jakarta.persistence.*; import java.time.Instant;
@Entity @Table(name="customer_addresses",indexes=@Index(name="idx_address_account_active",columnList="customer_account_id,active")) public class CustomerAddress{
 @Id @GeneratedValue(strategy=GenerationType.IDENTITY) private Long id;@Column(name="customer_account_id",nullable=false)private Long accountId;@Column(nullable=false,length=40)private String label;@Column(name="recipient_name",nullable=false,length=120)private String recipientName;@Column(nullable=false,length=20)private String phone;@Column(name="address_line1",nullable=false,length=250)private String addressLine1;@Column(name="address_line2",length=250)private String addressLine2;@Column(length=100)private String area;@Column(nullable=false,length=100)private String city;@Column(nullable=false,length=100)private String district;@Column(nullable=false,length=100)private String division;@Column(name="postal_code",length=20)private String postalCode;@Column(nullable=false,length=80)private String country="Bangladesh";@Column(name="delivery_instructions",length=500)private String instructions;@Column(name="default_address",nullable=false)private boolean defaultAddress;@Column(nullable=false)private boolean active=true;@Column(name="created_at",nullable=false,updatable=false)private Instant createdAt;@Column(name="updated_at",nullable=false)private Instant updatedAt;@Version private long version;
 @PrePersist void create(){createdAt=updatedAt=Instant.now();}@PreUpdate void update(){updatedAt=Instant.now();}
 public Long getId(){return id;}public Long getAccountId(){return accountId;}public void setAccountId(Long v){accountId=v;}public String getLabel(){return label;}public void setLabel(String v){label=v;}public String getRecipientName(){return recipientName;}public void setRecipientName(String v){recipientName=v;}public String getPhone(){return phone;}public void setPhone(String v){phone=v;}public String getAddressLine1(){return addressLine1;}public void setAddressLine1(String v){addressLine1=v;}public String getAddressLine2(){return addressLine2;}public void setAddressLine2(String v){addressLine2=v;}public String getArea(){return area;}public void setArea(String v){area=v;}public String getCity(){return city;}public void setCity(String v){city=v;}public String getDistrict(){return district;}public void setDistrict(String v){district=v;}public String getDivision(){return division;}public void setDivision(String v){division=v;}public String getPostalCode(){return postalCode;}public void setPostalCode(String v){postalCode=v;}public String getCountry(){return country;}public void setCountry(String v){country=v;}public String getInstructions(){return instructions;}public void setInstructions(String v){instructions=v;}public boolean isDefaultAddress(){return defaultAddress;}public void setDefaultAddress(boolean v){defaultAddress=v;}public boolean isActive(){return active;}public void setActive(boolean v){active=v;}
}
